#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define N 100000
#define M 100000
#define T 100000

int main() {
    int n, m, t, i, j, k, s[N], p[N];
    double dp[N][M], ans = 0.0;

    scanf("%d %d %d", &n, &m, &t);
    for (i = 0; i < n; i++) {
        scanf("%d", &s[i]);
    }
    for (i = 0; i < n; i++) {
        scanf("%d", &p[i]);
    }

    for (i = 0; i < n; i++) {
        for (j = 0; j < m; j++) {
            dp[i][j] = 0.0;
        }
    }

    for (i = 0; i < n; i++) {
        for (j = 0; j < m; j++) {
            if (j == 0) {
                dp[i][j] = s[i];
            } else {
                dp[i][j] = dp[i][j - 1] * (1 + p[i] / 1000000.0);
            }
        }
    }

    for (i = 0; i < n; i++) {
        for (j = 0; j < m; j++) {
            if (dp[i][j] > ans) {
                ans = dp[i][j];
            }
        }
    }

    for (i = 0; i < n; i++) {
        for (j = 0; j < m; j++) {
            if (ans <= t * (1 + p[i] / 1000000.0)) {
                ans = ans + t * (1 + p[i] / 1000000.0);
            } else {
                ans = ans + (ans - t * (1 + p[i] / 1000000.0)) * (1 + p[i] / 1000000.0);
            }
        }
    }

    printf("%.10f\n", ans);
    return 0;
}

